import { NextRequest, NextResponse } from "next/server"

/**
 * Korumalı rotalar — bu pattern'lerle başlayan URL'lere
 * oturum açmadan girilemez.
 */
const PROTECTED_PATTERNS = [
  "/dashboard",
  "/profile",
  "/jobs",
  "/messages",
  "/connections",
  "/feed",
]

const PUBLIC_PATHS = ["/", "/sign-in", "/sign-up", "/api/auth"]

function isProtected(pathname: string) {
  return PROTECTED_PATTERNS.some((p) => pathname.startsWith(p))
}

export async function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl

  // Public path'ler her zaman geçsin
  if (PUBLIC_PATHS.some((p) => pathname.startsWith(p))) {
    return NextResponse.next()
  }

  // Korumalı rota kontrolü — Better Auth session cookie
  if (isProtected(pathname)) {
    const sessionCookie =
      request.cookies.get("better-auth.session_token") ??
      request.cookies.get("__Secure-better-auth.session_token")

    if (!sessionCookie?.value) {
      const signInUrl = new URL("/sign-in", request.url)
      signInUrl.searchParams.set("callbackUrl", pathname)
      return NextResponse.redirect(signInUrl)
    }
  }

  return NextResponse.next()
}

export const config = {
  matcher: [
    // Static dosyaları, _next klasörünü ve favicon'ı atla
    "/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp)$).*)",
  ],
}
